package picod

import (
	"encoding/base64"
	"fmt"
	"io"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

func (s *Server) UploadFileHandler(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")

	if len(contentType) >= 9 && contentType[:9] == "multipart" {
		s.handleMultipartUpload(c)
		return
	}

	s.handleJSONBase64Upload(c)
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	path := c.PostForm("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required", "code": 400})
		return
	}

	fileHeader, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "file is required", "code": 400})
		return
	}

	modeStr := c.PostForm("mode")
	mode := parseFileMode(modeStr)

	safePath, err := sanitizePath(s.workspaceDir, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid path: %v", err), "code": 400})
		return
	}

	if err := os.MkdirAll(filepath.Dir(safePath), 0o755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directories: %v", err), "code": 500})
		return
	}

	file, err := fileHeader.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to open file: %v", err), "code": 500})
		return
	}
	defer file.Close()

	out, err := os.Create(safePath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create file: %v", err), "code": 500})
		return
	}
	defer out.Close()

	if _, err := io.Copy(out, file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err), "code": 500})
		return
	}

	if err := os.Chmod(safePath, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to set file mode: %v", err), "code": 500})
		return
	}

	relPath, _ := filepath.Rel(s.workspaceDir, safePath)
	if relPath == "" {
		relPath = path
	}

	fileInfo, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     fileInfo.Size(),
		Mode:     fmt.Sprintf("%o", mode),
		Modified: fileInfo.ModTime(),
	})
}

func (s *Server) handleJSONBase64Upload(c *gin.Context) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid JSON: %v", err), "code": 400})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid base64 content: %v", err), "code": 400})
		return
	}

	mode := parseFileMode(req.Mode)

	safePath, err := sanitizePath(s.workspaceDir, req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid path: %v", err), "code": 400})
		return
	}

	if err := os.MkdirAll(filepath.Dir(safePath), 0o755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to create directories: %v", err), "code": 500})
		return
	}

	if err := os.WriteFile(safePath, content, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to write file: %v", err), "code": 500})
		return
	}

	relPath, _ := filepath.Rel(s.workspaceDir, safePath)
	if relPath == "" {
		relPath = req.Path
	}

	fileInfo, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     int64(len(content)),
		Mode:     fmt.Sprintf("%o", mode),
		Modified: fileInfo.ModTime(),
	})
}

func parseFileMode(modeStr string) os.FileMode {
	if modeStr == "" {
		return 0o644
	}

	var mode int64
	if _, err := fmt.Sscanf(modeStr, "%o", &mode); err != nil {
		return 0o644
	}

	if mode > maxFileMode {
		mode = maxFileMode
	}

	return os.FileMode(mode)
}

func (s *Server) ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Missing 'path' query parameter", "code": 400})
		return
	}

	safePath, err := sanitizePath(s.workspaceDir, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("invalid path: %v", err), "code": 400})
		return
	}

	entries, err := os.ReadDir(safePath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "Directory not found", "code": 404})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to read directory: %v", err), "code": 500})
		}
		return
	}

	files := make([]FileEntry, 0, len(entries))
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}
		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     fmt.Sprintf("%o", info.Mode().Perm()),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func (s *Server) DownloadFileHandler(c *gin.Context) {
	path := strings.TrimPrefix(c.Param("path"), "/")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "path is required", "code": 400})
		return
	}

	safePath, err := sanitizePath(s.workspaceDir, path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("access denied: %v", err), "code": 400})
		return
	}

	info, err := os.Stat(safePath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": "File not found", "code": 404})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to stat file: %v", err), "code": 500})
		}
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Path is a directory, not a file", "code": 400})
		return
	}

	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(safePath)))
	c.Header("Content-Type", getContentType(safePath))

	c.File(safePath)
}

func getContentType(path string) string {
	ext := filepath.Ext(path)
	if ct := mime.TypeByExtension(ext); ct != "" {
		return ct
	}
	return "application/octet-stream"
}

