package store

import (
	"errors"
	"fmt"
	"os"
	"strings"
	"sync"

	"k8s.io/klog/v2"
)

const (
	redisStoreType  = "redis"
	valkeyStoreType = "valkey"
)

var (
	initStoreOnce sync.Once
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			klog.Fatalf("Failed to initialize store: %v", err)
		}
	})
	return provider
}

func initStore() error {
	storeType := os.Getenv("STORE_TYPE")
	if storeType == "" {
		storeType = redisStoreType
	}
	storeType = strings.ToLower(storeType)

	var err error
	switch storeType {
	case redisStoreType:
		provider, err = newRedisStore()
	case valkeyStoreType:
		provider, err = newValkeyStore()
	default:
		err = &UnsupportedStoreTypeError{Type: storeType}
	}

	if err != nil {
		return err
	}

	klog.Infof("Initialized %s session store", storeType)
	return nil
}

type UnsupportedStoreTypeError struct {
	Type string
}

func (e *UnsupportedStoreTypeError) Error() string {
	return "unsupported store type: " + e.Type + " (supported: redis, valkey)"
}

