package picod

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	TimeoutExitCode       = 124
	MaxBodySize           = 32 << 20
	PublicKeyEnvVar       = "PICOD_AUTH_PUBLIC_KEY"
	maxFileMode     int64 = 0o777
)

type Config struct {
	Port      int
	Workspace string
}

type Server struct {
	engine       *gin.Engine
	config       Config
	authManager  *AuthManager
	startTime    time.Time
	workspaceDir string
}

func NewServer(config Config) (*Server, error) {
	s := &Server{
		config:    config,
		startTime: time.Now(),
		engine:    gin.New(),
	}

	s.authManager = &AuthManager{}
	if err := s.authManager.LoadPublicKeyFromEnv(); err != nil {
		return nil, err
	}

	if err := s.setWorkspace(config.Workspace); err != nil {
		return nil, err
	}

	s.setupRoutes()

	return s, nil
}

func (s *Server) setWorkspace(workspace string) error {
	if workspace == "" {
		var err error
		workspace, err = os.Getwd()
		if err != nil {
			klog.Fatalf("Failed to get current working directory: %v", err)
			return err
		}
	} else {
		absPath, err := filepath.Abs(workspace)
		if err == nil {
			workspace = absPath
		}
	}

	if _, err := os.Stat(workspace); os.IsNotExist(err) {
		if err := os.MkdirAll(workspace, 0o755); err != nil {
			return err
		}
	}

	s.workspaceDir = workspace
	return nil
}

func (s *Server) Run() error {
	addr := ":" + itoa(s.config.Port)

	server := &http.Server{
		Addr:              addr,
		Handler:           s.engine,
		ReadHeaderTimeout: 10 * time.Second,
	}

	return server.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	addr := ":" + itoa(s.config.Port)

	server := &http.Server{
		Addr:    addr,
		Handler: s.engine,
	}

	return server.Shutdown(ctx)
}

func (s *Server) setupRoutes() {
	s.engine.Use(gin.Recovery())
	s.engine.Use(gin.Logger())

	if s.authManager.publicKey != nil {
		s.engine.Use(s.authManager.AuthMiddleware())
	}

	api := s.engine.Group("/api")
	{
		api.POST("/execute", s.ExecuteHandler)
		api.POST("/files", s.UploadFileHandler)
		api.GET("/files", s.ListFilesHandler)
		api.GET("/files/*path", s.DownloadFileHandler)
	}

	s.engine.GET("/health", s.HealthCheckHandler)
}

func (s *Server) HealthCheckHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "healthy",
		"service": "picod",
		"version": "0.1.0",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func itoa(i int) string {
	buf := make([]byte, 0, 10)
	return string(appendInt(buf, i))
}

func appendInt(buf []byte, i int) []byte {
	if i == 0 {
		return append(buf, '0')
	}
	for i > 0 {
		buf = append(buf, byte('0'+i%10))
		i /= 10
	}
	for i, j := 0, len(buf)-1; i < j; i, j = i+1, j-1 {
		buf[i], buf[j] = buf[j], buf[i]
	}
	return buf
}

