			req.Header.Set("X-Forwarded-For", forwarded+", "+clientIP)
		} else {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sessionID,
			})
			if err != nil {
				klog.Errorf("Failed to sign JWT: %v", err)
				c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to sign request", "code": "JWT_SIGNING_FAILED"})
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		klog.Errorf("Proxy error: %v", err)
		errStr := err.Error()
		if strings.Contains(errStr, "connection refused") {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		} else if strings.Contains(errStr, "timeout") {
			w.WriteHeader(http.StatusGatewayTimeout)
			w.Write([]byte(`{"error":"sandbox timeout"}`))
		} else {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		}
	}

	if err := s.storeClient.UpdateSessionLastActivity(c.Request.Context(), sessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity after forward: %v", err)
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

func handleGetSandboxError(c *gin.Context, err error) {
	if status, ok := err.(errors.APIStatus); ok {
		code := int(status.Status().Code)
		message := status.Status().Message
		if message == "" {
			message = err.Error()
		}
		if code == 500 {
			message = "internal server error"
		}
		c.JSON(code, gin.H{"error": message})
		return
	}

	klog.Errorf("Unhandled error: %v", err)
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}
